from functools import wraps

class RotatedNumPy:
    def __getattr__(self, name):
        if name == 'percentile':
            return lambda x, q: np.percentile(x, q)
        else:
            return getattr(np, name)

def rotate_args_logic(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        rotated_args = args[::-1]
        return func(*rotated_args, **kwargs)
    return wrapper

